try {
  const panelData = context.panel.data;
  if (!panelData || !panelData.series || panelData.series.length === 0) {
    return { title: { text: 'Sem dados — selecione um repositório', left: 'center', top: 'center' } };
  }

  function toArr(field) {
    if (!field) return [];
    const v = field.values;
    if (!v) return [];
    if (v.buffer) return Array.from(new Float64Array(v.buffer));
    if (Array.isArray(v)) return v;
    if (typeof v.toArray === 'function') return v.toArray();
    return Array.from(v);
  }

  const frame = panelData.series[0];
  if (!frame || frame.fields.length === 0) {
    return { title: { text: 'Query sem retorno', left: 'center', top: 'center' } };
  }

  const datetimes = toArr(frame.fields.find(f => f.name === 'datetime'));

  const characteristics = [
    { label: 'Confiabilidade', color: '#1D9E75', data: toArr(frame.fields.find(f => f.name === 'reliability')) },
    { label: 'Manutenibilidade', color: '#378ADD', data: toArr(frame.fields.find(f => f.name === 'maintainability')) },
    { label: 'Adequação Funcional', color: '#D85A30', data: toArr(frame.fields.find(f => f.name === 'functional_suitability')) },
  ];

  // releases da query B
  let releases = [];
  if (panelData.series.length > 1) {
    const rf = panelData.series[1];
    const rNames = toArr(rf.fields.find(f => f.name === 'release_name'));
    const rDates = toArr(rf.fields.find(f => f.name === 'release_date'));
    releases = rNames.map((name, i) => {
      const target = String(rDates[i] || '').slice(0, 10);
      let idx = datetimes.findIndex(d => String(d).slice(0, 10) >= target);
      if (idx < 0) idx = datetimes.length - 1;
      return { label: name, dateIndex: idx };
    });
  }

  // ── pulso ECG ──────────────────────────────────────────────────────────────
  function msgPulse(scores, idxList) {
    const SPS = 60;
    const pts = [];
    for (let ii = 0; ii < idxList.length - 1; ii++) {
      const a = scores[idxList[ii]] ?? 0, b = scores[idxList[ii + 1]] ?? 0;
      const delta = b - a, pk = delta * 2.2;
      for (let s = 0; s < SPS; s++) {
        const t = s / SPS;
        let v;
        if (t < 0.30) { v = a; }
        else if (t < 0.42) { const p = (t - 0.30) / 0.12; v = a + pk * Math.sin(p * Math.PI * 0.5); }
        else if (t < 0.56) { const p = (t - 0.42) / 0.14; v = a + pk * (1 - p); }
        else if (t < 0.68) { const p = (t - 0.56) / 0.12; v = b - delta * 0.15 * Math.sin(p * Math.PI); }
        else { v = b; }
        pts.push(Math.max(0.01, Math.min(0.99, v)));
      }
    }
    pts.push(Math.max(0.01, Math.min(0.99, scores[idxList[idxList.length - 1]] ?? 0)));
    return pts;
  }

  const N = datetimes.length;
  const idxList = Array.from({ length: N }, (_, i) => i);
  const SPS = 60;

  const xLabels = [];
  idxList.forEach((idx, ii) => {
    if (ii < idxList.length - 1) {
      for (let s = 0; s < SPS; s++) xLabels.push(datetimes[idx]);
    } else {
      xLabels.push(datetimes[idx]);
    }
  });

  const releaseLines = releases.map(r => ({
    xAxis: r.dateIndex * SPS,
    label: { formatter: r.label, position: 'insideStartTop', fontSize: 10, fontWeight: 'bold' },
    lineStyle: { color: '#BA7517', type: 'dashed', width: 1 },
  }));

  const isDark = context.grafana.theme.isDark;
  const textColor = isDark ? 'rgba(255,255,255,0.7)' : 'rgba(0,0,0,0.6)';
  const gridColor = isDark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)';

  const series = characteristics.map(c => ({
    name: c.label,
    type: 'line',
    smooth: false,
    symbol: 'none',
    lineStyle: { color: c.color, width: 1.5 },
    data: msgPulse(c.data, idxList),
    markLine: {
      silent: true,
      symbol: 'none',
      data: releaseLines,
    },
    markPoint: {
      symbol: 'circle',
      symbolSize: 6,
      data: releases.map(r => ({
        coord: [r.dateIndex * SPS, c.data[r.dateIndex] ?? 0],
        itemStyle: { color: c.color },
      })),
    },
  }));

  return {
    backgroundColor: 'transparent',
    legend: {
      data: characteristics.map(c => c.label),
      textStyle: { color: textColor, fontSize: 11 },
      bottom: 0,
    },
    tooltip: {
      trigger: 'axis',
      formatter: params => {
        const idx = Math.floor(params[0].dataIndex / SPS);
        const dt = datetimes[Math.min(idx, N - 1)];
        const rel = releases.find(r => r.dateIndex === idx);
        let html = `<b>${dt}</b>`;
        if (rel) html += `<br/><span style="color:#BA7517">● ${rel.label}</span>`;
        params.forEach(p => {
          html += `<br/><span style="color:${p.color}">■</span> ${p.seriesName}: <b>${(p.data ?? 0).toFixed(2)}</b>`;
        });
        return html;
      },
    },
    grid: { top: 20, bottom: 60, left: 50, right: 20 },
    xAxis: {
      type: 'category',
      data: xLabels,
      axisLabel: {
        showMaxLabel: true,
        interval: SPS * Math.floor(N / 5) - 1,
        color: textColor,
        fontSize: 10,
        formatter: v => v ? String(v).slice(5, 10).replace('-', '/') : '',
      },
      axisLine: { lineStyle: { color: gridColor } },
      splitLine: { show: false },
    },
    yAxis: {
      type: 'value',
      min: 0,
      max: 1,
      interval: 0.25,
      axisLabel: { color: textColor, fontSize: 9, formatter: v => v.toFixed(2) },
      splitLine: { lineStyle: { color: gridColor } },
    },
    series,
  };
} catch (e) {
  return { title: { text: 'Erro: ' + e.message, left: 'center', top: 'center' } };
}

