    { key: 'reliability', label: 'Confiabilidade', color: '#1D9E75', data: toArr(frame.fields.find(f => f.name === 'reliability')) },
    { key: 'maintainability', label: 'Manutenibilidade', color: '#378ADD', data: toArr(frame.fields.find(f => f.name === 'maintainability')) },
    { key: 'functional_suitability', label: 'Adequação Funcional', color: '#D85A30', data: toArr(frame.fields.find(f => f.name === 'functional_suitability')) },
